class RideObjects:
    """All ride objects, organized by category.

    Access by category:
        RideObjects.gentle.MERRY_GO_ROUND
        RideObjects.stall.BURGER_BAR

    Or iterate all:
        RideObjects.all()
    """

    gentle = _Gentle()
    rollercoaster = _Rollercoaster()
    stall = _Stall()
    thrill = _Thrill()
    transport = _Transport()
    water = _Water()

    @staticmethod
    def all() -> list[RideObjectInfo]:
        """Return all 155 ride objects."""
