    @staticmethod
    def by_identifier(identifier: str) -> RideObjectInfo | None:
        """Look up a ride object by its identifier string."""
        return _BY_IDENTIFIER.get(identifier)

    @staticmethod
    def by_ride_type(ride_type: str) -> list[RideObjectInfo]:
        """Return all objects for a given ride type string."""
        return [o for o in RideObjects.all() if o.ride_type == ride_type]


